import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useSocket } from '../../contexts/SocketContext';
import axios from 'axios';
import { ShoppingBagIcon, ArrowPathIcon, ChatBubbleLeftIcon } from '@heroicons/react/24/outline';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerDashboard = () => {
  const { user } = useAuth();
  const { sensorData } = useSocket();
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    totalSpent: 0,
    totalKg: 0,
    transactionCount: 0
  });

  useEffect(() => {
    fetchTransactions();
  }, []);

  const fetchTransactions = async () => {
    try {
      const response = await axios.get(`${API_URL}/transactions`);
      setTransactions(response.data);
      
      // Calculate stats
      const totalSpent = response.data.reduce((sum, t) => sum + t.amount_paid, 0);
      const totalKg = response.data.reduce((sum, t) => sum + t.quantity_kg, 0);
      
      setStats({
        totalSpent,
        totalKg,
        transactionCount: response.data.length
      });
    } catch (error) {
      console.error('Error fetching transactions:', error);
    } finally {
      setLoading(false);
    }
  };

  // Check if user needs to accept terms
  if (!user?.terms_accepted) {
    return (
      <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4 mb-6">
        <div className="flex">
          <div className="flex-shrink-0">
            <svg className="h-5 w-5 text-yellow-400" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
          </div>
          <div className="ml-3">
            <p className="text-sm text-yellow-700">
              You haven't accepted our terms and conditions yet.{' '}
              <Link to="/terms" className="font-medium underline text-yellow-700 hover:text-yellow-600">
                Click here to review and accept
              </Link>
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div>
      <h1 className="text-2xl font-semibold text-gray-900 mb-6">
        Welcome back, {user?.first_name}!
      </h1>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 gap-5 sm:grid-cols-3 mb-6">
        <div className="bg-white overflow-hidden shadow rounded-lg">
          <div className="p-5">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-green-100 rounded-md p-3">
                <ShoppingBagIcon className="h-6 w-6 text-green-600" />
              </div>
              <div className="ml-5 w-0 flex-1">
                <dl>
                  <dt className="text-sm font-medium text-gray-500 truncate">
                    Total Transactions
                  </dt>
                  <dd className="text-lg font-medium text-gray-900">
                    {stats.transactionCount}
                  </dd>
                </dl>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white overflow-hidden shadow rounded-lg">
          <div className="p-5">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-blue-100 rounded-md p-3">
                <span className="text-xl font-bold text-blue-600">₱</span>
              </div>
              <div className="ml-5 w-0 flex-1">
                <dl>
                  <dt className="text-sm font-medium text-gray-500 truncate">
                    Total Spent
                  </dt>
                  <dd className="text-lg font-medium text-gray-900">
                    ₱{stats.totalSpent.toFixed(2)}
                  </dd>
                </dl>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white overflow-hidden shadow rounded-lg">
          <div className="p-5">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-yellow-100 rounded-md p-3">
                <span className="text-xl font-bold text-yellow-600">kg</span>
              </div>
              <div className="ml-5 w-0 flex-1">
                <dl>
                  <dt className="text-sm font-medium text-gray-500 truncate">
                    Total Rice Purchased
                  </dt>
                  <dd className="text-lg font-medium text-gray-900">
                    {stats.totalKg.toFixed(2)} kg
                  </dd>
                </dl>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Machine Status */}
      {sensorData && (
        <div className="bg-white shadow rounded-lg p-6 mb-6">
          <h2 className="text-lg font-medium text-gray-900 mb-4">Machine Status</h2>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <p className="text-sm text-gray-500">Sinandomeng Stock</p>
              <p className={`text-lg font-semibold ${
                sensorData.container_1_stock === 'OK' ? 'text-green-600' : 
                sensorData.container_1_stock === 'LOW' ? 'text-yellow-600' : 'text-red-600'
              }`}>
                {sensorData.container_1_level.toFixed(1)} kg ({sensorData.container_1_stock})
              </p>
            </div>
            <div>
              <p className="text-sm text-gray-500">Dinorado Stock</p>
              <p className={`text-lg font-semibold ${
                sensorData.container_2_stock === 'OK' ? 'text-green-600' : 
                sensorData.container_2_stock === 'LOW' ? 'text-yellow-600' : 'text-red-600'
              }`}>
                {sensorData.container_2_level.toFixed(1)} kg ({sensorData.container_2_stock})
              </p>
            </div>
            <div>
              <p className="text-sm text-gray-500">Machine Status</p>
              <p className={`text-lg font-semibold ${
                sensorData.machine_status === 'ACTIVE' ? 'text-green-600' : 'text-red-600'
              }`}>
                {sensorData.machine_status}
              </p>
            </div>
            <div>
              <p className="text-sm text-gray-500">Temperature</p>
              <p className="text-lg font-semibold text-gray-900">
                {sensorData.temperature}°C
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Recent Transactions */}
      <div className="bg-white shadow rounded-lg">
        <div className="px-4 py-5 sm:px-6 flex justify-between items-center">
          <h2 className="text-lg font-medium text-gray-900">Recent Transactions</h2>
          <Link
            to="/customer/transactions"
            className="text-sm text-green-600 hover:text-green-800"
          >
            View all
          </Link>
        </div>
        <div className="border-t border-gray-200">
          {loading ? (
            <p className="p-4 text-center text-gray-500">Loading...</p>
          ) : transactions.length === 0 ? (
            <p className="p-4 text-center text-gray-500">No transactions yet</p>
          ) : (
            <ul className="divide-y divide-gray-200">
              {transactions.slice(0, 5).map((transaction) => (
                <li key={transaction.id} className="px-4 py-4 sm:px-6 hover:bg-gray-50">
                  <div className="flex items-center justify-between">
                    <div className="flex-1">
                      <p className="text-sm font-medium text-gray-900">
                        {transaction.rice_type} - {transaction.quantity_kg} kg
                      </p>
                      <p className="text-sm text-gray-500">
                        {new Date(transaction.timestamp).toLocaleDateString()} at{' '}
                        {new Date(transaction.timestamp).toLocaleTimeString()}
                      </p>
                    </div>
                    <div className="ml-4">
                      <p className="text-sm font-semibold text-gray-900">
                        ₱{transaction.amount_paid}
                      </p>
                      <Link
                        to={`/customer/rate/${transaction.transaction_id}`}
                        className="text-xs text-green-600 hover:text-green-800"
                      >
                        Rate this purchase
                      </Link>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>

      {/* Quick Actions */}
      <div className="mt-6 grid grid-cols-2 gap-4">
        <Link
          to="/customer/returns/create"
          className="bg-white shadow rounded-lg p-6 text-center hover:shadow-md transition-shadow"
        >
          <ArrowPathIcon className="h-8 w-8 mx-auto text-blue-600 mb-2" />
          <h3 className="text-sm font-medium text-gray-900">Request Return</h3>
          <p className="text-xs text-gray-500 mt-1">Return a product</p>
        </Link>
        <Link
          to="/customer/messages"
          className="bg-white shadow rounded-lg p-6 text-center hover:shadow-md transition-shadow"
        >
          <ChatBubbleLeftIcon className="h-8 w-8 mx-auto text-purple-600 mb-2" />
          <h3 className="text-sm font-medium text-gray-900">Contact Support</h3>
          <p className="text-xs text-gray-500 mt-1">Send us a message</p>
        </Link>
      </div>
    </div>
  );
};

export default CustomerDashboard;
